// nextPageURL preserves the current filter when paginating forward —
// the cursor is the only value that changes between page requests.
func nextPageURL(f EventsFilter, cursor string) string {
	q := "/events?cursor=" + cursor
	if f.HostID != "" {
		q += "&host_id=" + f.HostID
	}
	if f.ClassUID != "" {
		q += "&class_uid=" + f.ClassUID
	}
	if f.SeverityID != "" {
		q += "&severity_id=" + f.SeverityID
	}
	if f.Since != "" {
		q += "&since=" + f.Since
	}
	if f.Until != "" {
		q += "&until=" + f.Until
	}
	return q
}

