// joinTokens concatenates a slice for display in the unknown-token
// hint above the events list. Inlined so the templ doesn't pull
// strings.Join.
func joinTokens(toks []string) string {
	out := ""
	for i, t := range toks {
		if i > 0 {
			out += " "
		}
		out += t
	}
	return out
}

